class Solution:
    def countOfPairs(self, n: int, x: int, y: int) -> list:
        # Analytical solution: for each pair (a,b) with a<b compute min distance
        # direct = b - a; via shortcut = min(|a-x|+1+|b-y|, |a-y|+1+|b-x|) (if x!=y)
        if x > y:
            x, y = y, x
        result = [0] * n
        for a in range(1, n+1):
            for b in range(a+1, n+1):
                direct = b - a
                if x == y:
                    d = direct
                else:
                    via1 = abs(a - x) + 1 + abs(b - y)
                    via2 = abs(a - y) + 1 + abs(b - x)
                    d = min(direct, via1, via2)
                result[d-1] += 2
        return result

