var countOfPairs = function(n, x, y) {
    if (x > y) { let t = x; x = y; y = t; }
    const result = new Array(n).fill(0);
    for (let a = 1; a <= n; a++) {
        for (let b = a + 1; b <= n; b++) {
            const direct = b - a;
            let d = direct;
            if (x !== y) {
                const via1 = Math.abs(a - x) + 1 + Math.abs(b - y);
                const via2 = Math.abs(a - y) + 1 + Math.abs(b - x);
                d = Math.min(direct, via1, via2);
            }
            result[d-1] += 2;
        }
    }
    return result;
};
